  1→//! Scoring engine for comparing specialist findings against benchmark ground truth.
  2→//!
  3→//! Uses location proximity and keyword overlap to match findings, then computes
  4→//! recall, precision, and weighted composite scores.
  5→
  6→use std::collections::HashSet;
  7→use std::fmt;
  8→
  9→use forge::autoresearch::benchmarks::{Expected, ExpectedFinding, MustNotFlag};
 10→
 11→/// A finding produced by a specialist agent.
 12→#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
 13→pub struct Finding {
 14→    pub severity: String,
 15→    pub file: String,
 16→    pub line: Option<u32>,
 17→    pub issue: String,
 18→    pub suggestion: String,
 19→}
 20→
 21→/// Composite score for a specialist's performance on benchmarks.
 22→#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
 23→pub struct SpecialistScore {
 24→    pub recall: f64,
 25→    pub precision: f64,
 26→    pub actionability: f64,
 27→    pub composite: f64,
 28→}
 29→
 30→impl fmt::Display for SpecialistScore {
 31→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 32→        write!(
 33→            f,
 34→            "recall={:.1}% precision={:.1}% actionability={:.1}% composite={:.1}%",
 35→            self.recall * 100.0,
 36→            self.precision * 100.0,
 37→            self.actionability * 100.0,
 38→            self.composite * 100.0,
 39→        )
 40→    }
 41→}
 42→
 43→/// Parsed location from an expected finding's location string.
 44→#[derive(Debug, Clone, PartialEq)]
 45→pub struct ParsedLocation {
 46→    pub file: Option<String>,
 47→    pub start_line: Option<u32>,
 48→    pub end_line: Option<u32>,
 49→}
 50→
 51→const LINE_TOLERANCE: u32 = 5;
 52→const MUST_FIND_OVERLAP_THRESHOLD: f64 = 0.50;
 53→const MUST_NOT_FLAG_OVERLAP_THRESHOLD: f64 = 0.60;
 54→
 55→const STOP_WORDS: &[&str] = &[
 56→    "the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
 57→    "in", "on", "at", "to", "for", "of", "with", "and", "or", "but",
 58→    "not", "this", "that", "it", "its",
 59→];
 60→
 61→/// Parse a line range string like `"42-45"` or `"42"` into start/end line numbers.
 62→fn parse_line_range(s: &str) -> (Option<u32>, Option<u32>) {
 63→    if let Some(dash_pos) = s.find('-') {
 64→        let start = s[..dash_pos].parse::<u32>().ok();
 65→        let end = s[dash_pos + 1..].parse::<u32>().ok();
 66→        (start, end)
 67→    } else {
 68→        let line = s.parse::<u32>().ok();
 69→        (line, line)
 70→    }
 71→}
 72→
 73→/// Parse a location string like `"code.rs:42-45"`, `"code.rs:42"`, `"line 42-45"`,
 74→/// `"line 42"`, or `""` into a [`ParsedLocation`].
 75→pub fn parse_location(location: &str) -> ParsedLocation {
 76→    let location = location.trim();
 77→    if location.is_empty() {
 78→        return ParsedLocation {
 79→            file: None,
 80→            start_line: None,
 81→            end_line: None,
 82→        };
 83→    }
 84→
 85→    // "line 42-45" or "line 42"
 86→    if let Some(line_part) = location.strip_prefix("line ") {
 87→        let (start, end) = parse_line_range(line_part);
 88→        return ParsedLocation {
 89→            file: None,
 90→            start_line: start,
 91→            end_line: end,
 92→        };
 93→    }
 94→
 95→    // "file.rs:42-45" or "file.rs:42"
 96→    if let Some(colon_pos) = location.rfind(':') {
 97→        let file = &location[..colon_pos];
 98→        let line_part = &location[colon_pos + 1..];
 99→        let (start, end) = parse_line_range(line_part);
100→        if start.is_some() {
101→            return ParsedLocation {
102→                file: Some(file.to_string()),
103→                start_line: start,
104→                end_line: end,
105→            };
106→        }
107→    }
108→
109→    // Bare filename
110→    ParsedLocation {
111→        file: Some(location.to_string()),
112→        start_line: None,
113→        end_line: None,
114→    }
115→}
116→
117→/// Tokenize a string: lowercase, split on non-alphanumeric, remove stop words.
118→fn tokenize(s: &str) -> Vec<String> {
119→    s.to_lowercase()
120→        .split(|c: char| !c.is_alphanumeric())
121→        .filter(|w| !w.is_empty())
122→        .filter(|w| !STOP_WORDS.contains(w))
123→        .map(|w| w.to_string())
124→        .collect()
125→}
126→
127→/// Compute keyword overlap between an expected description and a finding description.
128→///
129→/// Returns `intersection_count / expected_token_count`, or `0.0` if the expected
130→/// string has zero non-stop tokens.
131→pub fn keyword_overlap(expected_desc: &str, finding_desc: &str) -> f64 {
132→    let expected_tokens: HashSet<String> = tokenize(expected_desc).into_iter().collect();
133→    if expected_tokens.is_empty() {
134→        return 0.0;
135→    }
136→    let finding_tokens: HashSet<String> = tokenize(finding_desc).into_iter().collect();
137→    let intersection = expected_tokens.intersection(&finding_tokens).count();
138→    intersection as f64 / expected_tokens.len() as f64
139→}
140→
141→/// Check if a finding's file and line match a parsed location within [`LINE_TOLERANCE`].
142→fn location_matches(finding: &Finding, loc: &ParsedLocation) -> bool {
143→    if let Some(ref expected_file) = loc.file
144→        && finding.file != *expected_file
145→    {
146→        return false;
147→    }
148→    if let (Some(start), Some(end)) = (loc.start_line, loc.end_line) {
149→        match finding.line {
150→            Some(finding_line) => {
151→                let range_start = start.saturating_sub(LINE_TOLERANCE);
152→                let range_end = end.saturating_add(LINE_TOLERANCE);
153→                if finding_line < range_start || finding_line > range_end {
154→                    return false;
155→                }
156→            }
157→            None => return false,
158→        }
159→    }
160→    true
161→}
162→
163→/// Matches specialist findings against benchmark ground truth.
164→pub struct FindingMatcher;
165→
166→impl FindingMatcher {
167→    /// Check if a finding matches an expected finding using location proximity
168→    /// (±5 lines) AND keyword overlap (>50%). Both must pass when location is present.
169→    pub fn matches_expected(finding: &Finding, expected: &ExpectedFinding) -> bool {
170→        let loc = parse_location(&expected.location);
171→        let has_location = loc.file.is_some() || loc.start_line.is_some();
172→
173→        let overlap = keyword_overlap(&expected.description, &finding.issue);
174→        let keyword_match = overlap > MUST_FIND_OVERLAP_THRESHOLD;
175→
176→        if has_location {
177→            location_matches(finding, &loc) && keyword_match
178→        } else {
179→            keyword_match
180→        }
181→    }
182→
183→    /// Check if a finding matches a must-not-flag entry using keyword overlap (>60%)
184→    /// OR location match. Either condition triggers a match.
185→    pub fn matches_must_not_flag(finding: &Finding, must_not: &MustNotFlag) -> bool {
186→        let overlap = keyword_overlap(&must_not.description, &finding.issue);
187→        if overlap > MUST_NOT_FLAG_OVERLAP_THRESHOLD {
188→            return true;
189→        }
190→
191→        if let Some(ref loc_str) = must_not.location {
192→            let loc = parse_location(loc_str);
193→            if location_matches(finding, &loc) {
194→                return true;
195→            }
196→        }
197→
198→        false
199→    }
200→}
201→
202→/// Computes recall, precision, and composite scores.
203→pub struct Scorer;
204→
205→impl Scorer {
206→    /// Score specialist findings against expected outcomes.
207→    ///
208→    /// - `recall` = matched_must_finds / total_must_finds (0 must_finds => 1.0)
209→    /// - `precision` = 1.0 - false_positives / total_findings (0 findings => 1.0)
210→    /// - `composite` = 0.4 * recall + 0.3 * precision + 0.3 * actionability
211→    pub fn score(findings: &[Finding], expected: &Expected, actionability: f64) -> SpecialistScore {
212→        let total_must_finds = expected.must_find.len();
213→        let matched = expected
214→            .must_find
215→            .iter()
216→            .filter(|ef| {
217→                findings
218→                    .iter()
219→                    .any(|f| FindingMatcher::matches_expected(f, ef))
220→            })
221→            .count();
222→        let recall = if total_must_finds == 0 {
223→            1.0
224→        } else {
225→            matched as f64 / total_must_finds as f64
226→        };
227→
228→        let total_findings = findings.len();
229→        let false_positives = findings
230→            .iter()
231→            .filter(|f| {
232→                expected
233→                    .must_not_flag
234→                    .iter()
235→                    .any(|mnf| FindingMatcher::matches_must_not_flag(f, mnf))
236→            })
237→            .count();
238→        let precision = if total_findings == 0 {
239→            1.0
240→        } else {
241→            1.0 - false_positives as f64 / total_findings as f64
242→        };
243→
244→        let composite = 0.4 * recall + 0.3 * precision + 0.3 * actionability;
245→
246→        SpecialistScore {
247→            recall,
248→            precision,
249→            actionability,
250→            composite,
251→        }
252→    }
253→}
